mapper.select:
SELECT p.id, p.title, p.content, p.start_date, p.end_date, p.max_people, p.budget, p.view_count, p.status, p.created_at, u.user_name FROM posts p JOIN users u ON p.user_id = u.id
AND ( p.title LIKE CONCAT('%', #{keyword}, '%') OR p.content LIKE CONCAT('%', #{keyword}, '%') OR u.user_name LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY p.id DESC LIMIT #{size} OFFSET #{offset}

mapper.update:
UPDATE posts
SET view_count = view_count + 1
WHERE id = #{id}

UPDATE posts
SET
    title = #{title},
    content = #{content},
    start_date = #{startDate},
    end_date = #{endDate},
    max_people = #{maxPeople},
    budget = #{budget}
WHERE id = #{id}
  AND user_id = #{userId}

UPDATE posts
SET status = #{status}
WHERE id = #{id}
  AND user_id = #{userId}
